CREATE OR REPLACE VIEW vm_mem_m_membership_registered (membership_no, application_form_no, member_group_no, prename_code, member_name, member_surname, id_card, sex, marriage_status, date_of_birth, present_address, approve_date, level_code, remark, member_status_code, resignation_approve_date, total_loan_int, present_moo, present_road, present_tambol, present_district_code, present_province_code, present_postcode, mem_type, group_position, bank_acc_no, reward_hbd_status, salary_amount, position_long, memo_notify, telephone, address_present, address_permanent, email, election_group_name, mobile_no) AS select
        sc_mem_m_membership_registered.membership_no,
        APPLICATION_FORM_NO
        ,MEMBER_GROUP_NO
        ,PRENAME_CODE,
        MEMBER_NAME,
        MEMBER_SURNAME,
        sc_mem_m_membership_registered.id_card,
        SEX,
        MARRIAGE_STATUS,
         SC_MEM_M_MEMBERSHIP_REGISTERED.DATE_OF_BIRTH,
         (select SC_MEM_M_MEMBER_ADDRESS.ADDRESS_NO 
         FROM SC_MEM_M_MEMBER_ADDRESS 
         WHERE SC_MEM_M_MEMBER_ADDRESS.MEMBERSHIP_NO = SC_MEM_M_MEMBERSHIP_REGISTERED.MEMBERSHIP_NO
         and address_type = '0')as present_address,
         SC_MEM_M_MEMBERSHIP_REGISTERED.APPROVE_DATE,
         null as level_code,
         sc_mem_m_membership_registered.remark,
         sc_mem_m_membership_registered.member_status_code,
         sc_mem_m_membership_registered.resignation_approve_date,
         SC_MEM_M_MEMBERSHIP_REGISTERED.TOTAL_LOAN_INT,
         (select MOO 
         FROM SC_MEM_M_MEMBER_ADDRESS 
         WHERE SC_MEM_M_MEMBER_ADDRESS.MEMBERSHIP_NO = SC_MEM_M_MEMBERSHIP_REGISTERED.MEMBERSHIP_NO
          and address_type = '0') as PRESENT_MOO,
         (select ROAD 
         FROM SC_MEM_M_MEMBER_ADDRESS 
         WHERE SC_MEM_M_MEMBER_ADDRESS.MEMBERSHIP_NO = SC_MEM_M_MEMBERSHIP_REGISTERED.MEMBERSHIP_NO
         and address_type = '0') as PRESENT_ROAD,
         
   
         ( select  pka_com_function.fp_get_sub_district_name( SC_MEM_M_MEMBER_ADDRESS.tambol )
         FROM SC_MEM_M_MEMBER_ADDRESS         
         where 1=1        
         and SC_MEM_M_MEMBER_ADDRESS.MEMBERSHIP_NO = SC_MEM_M_MEMBERSHIP_REGISTERED.MEMBERSHIP_NO
         and address_type = '0') as PRESENT_TAMBOL,
         
         (select DISTRICT_CODE 
         from SC_MEM_M_MEMBER_ADDRESS 
         WHERE SC_MEM_M_MEMBER_ADDRESS.MEMBERSHIP_NO = SC_MEM_M_MEMBERSHIP_REGISTERED.MEMBERSHIP_NO
         and address_type = '0') AS PRESENT_DISTRICT_CODE,
         (select PROVINCE_CODE 
         from SC_MEM_M_MEMBER_ADDRESS 
         WHERE SC_MEM_M_MEMBER_ADDRESS.MEMBERSHIP_NO = SC_MEM_M_MEMBERSHIP_REGISTERED.MEMBERSHIP_NO
         and address_type = '0') as PRESENT_PROVINCE_CODE,
         (select POSTCODE 
         from SC_MEM_M_MEMBER_ADDRESS 
         WHERE SC_MEM_M_MEMBER_ADDRESS.MEMBERSHIP_NO = SC_MEM_M_MEMBERSHIP_REGISTERED.MEMBERSHIP_NO
         and address_type = '0') as PRESENT_POSTCODE,
         SC_MEM_M_MEMBERSHIP_REGISTERED.MEM_TYPE,
         null as GROUP_POSITION,
        '' AS BANK_ACC_NO,
        null as reward_hbd_status
 
        ,( SELECT
                salary_amount
            FROM
                sc_mem_m_member_work_info
            WHERE
                sc_mem_m_member_work_info.membership_no = sc_mem_m_membership_registered.membership_no
        ) AS salary_amount 
        ,( SELECT
                position_long
            FROM
                sc_mem_m_member_work_info
            WHERE
                sc_mem_m_member_work_info.membership_no = sc_mem_m_membership_registered.membership_no
        ) AS position_long 
        ,(  SELECT
                memo_detail
            FROM
                sc_mem_m_member_memo
            WHERE
                sc_mem_m_member_memo.membership_no = sc_mem_m_membership_registered.membership_no
                AND seq_no = (
                    SELECT
                        MAX(seq_no)
                    FROM
                        sc_mem_m_member_memo
                    WHERE
                        sc_mem_m_member_memo.notify_status = '1'
                        AND sc_mem_m_member_memo.membership_no = sc_mem_m_membership_registered.membership_no
                ) 
        ) AS MEMO_NOTIFY  ,
        (SELECT telephone
          FROM sc_mem_m_member_address
          WHERE membership_no = sc_mem_m_membership_registered.membership_no
          AND address_type = '0') as TELEPHONE,
PKA_COM_FUNCTION.FP_GET_MEMBER_ADDRESS_PRES(SC_MEM_M_MEMBERSHIP_REGISTERED.MEMBERSHIP_NO) as ADDRESS_PRESENT,
pka_com_function.fp_get_member_address_perm(sc_mem_m_membership_registered.membership_no) as ADDRESS_PERMANENT
,SC_MEM_M_MEMBERSHIP_REGISTERED.EMAIL 
--,( select ( select  election_zone_name 
